import React, {createContext, useCallback, useContext, useEffect, useMemo, useState} from 'react';
import type {ColorMode, IKitsTheme, IKitsThemeContextValues, KitsThemeOverride} from '@lmb/kitsconcerto-types';
import {defaultTheme, deepMerge, resolveTokenValue} from '@lmb/kitsconcerto-types';
import {useColorScheme} from 'react-native';
import {buildNativeColorMap} from './resolvers.native';
import {setActiveColorMap} from '@lmb/kitsconcertomobile/Factory/helpers/style';

const KitsThemeContext = createContext<IKitsThemeContextValues | null>(null);

/** Context for the resolved native color map, consumed by style.ts */
const NativeColorMapContext = createContext<Record<string, string>>({});

export interface KitsThemeProviderProps {
    theme?: KitsThemeOverride;
    children: React.ReactNode;
}

export function KitsThemeProvider({theme: themeOverride, children}: KitsThemeProviderProps) {
    const mergedTheme = useMemo(
        () => (themeOverride ? deepMerge(defaultTheme, themeOverride as Record<string, any>) as IKitsTheme : defaultTheme),
        [themeOverride],
    );

    const systemScheme = useColorScheme();
    const [colorMode, setColorMode] = useState<ColorMode>(mergedTheme.config.initialColorMode);

    const toggleColorMode = useCallback(
        () => setColorMode(m => (m === 'light' ? 'dark' : 'light')),
        [],
    );

    // System color mode detection
    useEffect(() => {
        if (mergedTheme.config.useSystemColorMode && systemScheme) {
            setColorMode(systemScheme);
        }
    }, [systemScheme, mergedTheme.config.useSystemColorMode]);

    // Build native color map and sync it to the style module
    const resolvedColorMap = useMemo(
        () => buildNativeColorMap(mergedTheme, colorMode),
        [mergedTheme, colorMode],
    );

    // Set synchronously during render so children have the correct color map
    // on their first render (useEffect would fire too late).
    setActiveColorMap(resolvedColorMap);

    const resolveToken = useCallback(
        (token: string) => resolveTokenValue(mergedTheme, colorMode, token, 'native'),
        [mergedTheme, colorMode],
    );

    const value = useMemo<IKitsThemeContextValues>(
        () => ({theme: mergedTheme, colorMode, toggleColorMode, setColorMode, resolveToken}),
        [mergedTheme, colorMode, toggleColorMode, resolveToken],
    );

    return (
        <KitsThemeContext.Provider value={value}>
            <NativeColorMapContext.Provider value={resolvedColorMap}>
                {children}
            </NativeColorMapContext.Provider>
        </KitsThemeContext.Provider>
    );
}

export function useKitsTheme(): IKitsThemeContextValues {
    const ctx = useContext(KitsThemeContext);
    if (!ctx) {
        return {
            theme: defaultTheme,
            colorMode: 'light',
            toggleColorMode: () => {},
            setColorMode: () => {},
            resolveToken: (token: string) => resolveTokenValue(defaultTheme, 'light', token, 'native'),
        };
    }
    return ctx;
}

/** Returns the resolved native color map for use in style functions */
export function useNativeColorMap(): Record<string, string> {
    return useContext(NativeColorMapContext);
}

export {KitsThemeContext, NativeColorMapContext};
